{"version":"NotebookV1","origId":1083584440949848,"name":"10-5 Log Scale","language":"scala","commands":[{"version":"CommandV1","origId":1083584440949849,"guid":"b671ca83-a0a0-4a85-89ff-eed15da0699c","subtype":"command","commandType":"auto","position":1.0,"command":"\n%md\n# Log Scale\n\nIn the lab, you will improve your model performance by transforming the label to log scale, predicting on log scale, then exponentiating to evaluate the result. ","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"37d2455d-ae79-4d31-93a2-e642c47a8354"},{"version":"CommandV1","origId":1083584440949850,"guid":"39d00897-cebb-45b8-b9b6-ffcf7009571e","subtype":"command","commandType":"auto","position":2.0,"command":"val filePath = \"/databricks-datasets/learning-spark-v2/sf-airbnb/sf-airbnb-clean.parquet\"\nval airbnbDF = spark.read.parquet(filePath)\nval Array(trainDF, testDF) = airbnbDF.randomSplit(Array(.8, .2), seed=42)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivot